import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  ArrowUpRight, 
  Smartphone, 
  Play, 
  TrendingUp,
  Droplet,
  Layers,
  MousePointer2
} from 'lucide-react';

export const ServiceBento = () => {
