interface PortfolioGridProps {
  activeCategory: string;
}

const PortfolioCard = ({ work, index }: { work: any; index: number }) => {
  const [isHovered, setIsHovered] = useState(false);

  const handleClick = () => {
    if (work.youtubeId) {
      window.open(`https://youtube.com/shorts/${work.youtubeId}`, '_blank');
    }
  };

  return (
    <motion.div
      layout
      initial={{ opacity: 0, scale: 0.9, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.9, y: 20 }}
      transition={{ 
        duration: 0.4, 
        delay: index * 0.05,
        type: "spring",
        stiffness: 100,
        damping: 15
      }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onClick={handleClick}
      className="relative group overflow-hidden rounded-[2.5rem] bg-zinc-900 border border-white/10 aspect-[9/16] cursor-pointer"
    >
      {/* Mock Video UI / Info */}
      <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 z-20 flex flex-col justify-end p-8 pointer-events-none">
        <div className="flex justify-between items-end">
          <div>
            <p className="text-[10px] font-black tracking-widest text-red-500 uppercase mb-1">{work.category}</p>
            <h4 className="text-xl font-bold text-white">{work.title}</h4>
          </div>
          <div className="w-12 h-12 rounded-full bg-white text-black flex items-center justify-center transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all shadow-xl">
            <ArrowUpRight size={24} />
          </div>
        </div>
      </div>

      {/* Video Overlay / Player */}
      <AnimatePresence>
        {isHovered && work.youtubeId && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="absolute inset-0 z-10 bg-black"
          >
            <iframe
              className="w-full h-full pointer-events-none scale-[1.3]"
              src={`https://www.youtube.com/embed/${work.youtubeId}?autoplay=1&mute=1&controls=0&loop=1&playlist=${work.youtubeId}&modestbranding=1&rel=0`}
              title={work.title}
              frameBorder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            ></iframe>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Thumbnail */}
      <div className={`absolute inset-0 flex items-center justify-center z-0 ${isHovered && work.youtubeId ? 'opacity-0' : 'opacity-100'} transition-opacity duration-300`}>
         <div className="w-16 h-16 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center text-white/40 group-hover:scale-110 group-hover:bg-red-500 group-hover:text-white transition-all shadow-2xl z-10">
            {work.youtubeId ? <Play size={24} fill="currentColor" /> : <MousePointer2 size={24} />}
         </div>
      </div>

      <img 
        src={work.youtubeId 
          ? `https://img.youtube.com/vi/${work.youtubeId}/maxresdefault.jpg` 
          : `https://images.unsplash.com/photo-${work.imgId}?auto=format&fit=crop&q=80&w=800&h=1200`
        } 
        className={`w-full h-full object-cover opacity-40 grayscale group-hover:grayscale-0 group-hover:opacity-80 transition-all duration-700 group-hover:scale-105 ${isHovered && work.youtubeId ? 'opacity-0' : 'opacity-40'}`}
        alt={work.title}
        onError={(e) => {
          // Fallback if maxresdefault doesn't exist for a video
          if(work.youtubeId) (e.target as HTMLImageElement).src = `https://img.youtube.com/vi/${work.youtubeId}/0.jpg`;
        }}
      />
    </motion.div>
  );
};

export const PortfolioGrid: React.FC<PortfolioGridProps> = ({ activeCategory }) => {
  const allWorks = [
    // Real Estate
    { title: 'Premium Property Edit', category: 'Real Estate', type: 'portrait', youtubeId: 'r-dFqVZqWww' },
    { title: 'Luxury Penthouse Tour', category: 'Real Estate', type: 'portrait', imgId: '1600585154343-be3824137071' },
    { title: 'Modern Villa Reveal', category: 'Real Estate', type: 'portrait', imgId: '1580587767376-0a25da100e1a' },
    { title: 'Oceanfront Lifestyle', category: 'Real Estate', type: 'portrait', imgId: '1512917774080-9991f1c4c750' },

    // Social
    { title: 'Personal Brand Vlog', category: 'Social', type: 'portrait', imgId: '1574717024653-61fd2cf4d44d' },
    { title: 'Gym Motivation Reel', category: 'Social', type: 'portrait', imgId: '1534438327276-14e5300c3a48' },
    { title: 'Travel Montage', category: 'Social', type: 'portrait', imgId: '1507525428034-b723cf961d3e' },

    // Business
    { title: 'Tech Product Launch', category: 'Business', type: 'portrait', imgId: '1460925895917-afdab827c52f' },
    { title: 'Corporate Interview', category: 'Business', type: 'portrait', imgId: '1573164773510-7e44a2c146e2' },
    { title: 'Startup Pitch Video', category: 'Business', type: 'portrait', imgId: '1542744094-24638eff58bb' },
  ];

  const filteredWorks = allWorks.filter(work => work.category === activeCategory);

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 min-h-[600px]">
      <AnimatePresence mode="popLayout">
        {filteredWorks.map((work, i) => (
          <PortfolioCard key={`${work.category}-${i}`} work={work} index={i} />
        ))}
      </AnimatePresence>
    </div>
  );
};

